SELECT device_id, device_type
FROM network_devices
WHERE device_type = 'Router';

SELECT COUNT(alert_id) AS resolved_alerts_count
FROM alerts
WHERE resolved = 1 AND alert_date BETWEEN '2023-07-01' AND '2023-07-31';

SELECT COUNT(*) AS total_online_devices
FROM network_devices
WHERE status = 'online';

SELECT vendor_name, contact_info
FROM vendors
WHERE vendor_id = 1;

SELECT COUNT(*) AS note_count
FROM notes
WHERE created_at LIKE '2023-08-%';

SELECT vendor_name, COUNT(vendor_id) AS vendor_count
FROM vendors
GROUP BY vendor_name;

SELECT COUNT(device_id) AS total_devices
FROM network_devices
WHERE vendor_id = (SELECT vendor_id FROM vendors WHERE vendor_name = 'Cisco Systems');
